codeExample:
// Fora de loop: o compilador já otimiza isso com StringBuilder internamente
String mensagem = "Olá, " + nome + "! Você tem " + idade + " anos.";

// Dentro de loop: StringBuilder explícito evita criar N objetos String intermediários
StringBuilder sb = new StringBuilder();
for (int i = 0; i < 10_000; i++) {
    sb.append("item ").append(i).append("\n"); // muta o MESMO buffer, sem criar objeto novo
}
String resultado = sb.toString(); // só converte pra String uma vez, no final

codeExampleBad:
// Cada + dentro do loop cria um novo objeto String e descarta o anterior.
// Com 10.000 iterações, isso significa milhares de objetos intermediários no lixo.
String resultado = "";
for (int i = 0; i < 10_000; i++) {
    resultado = resultado + "item " + i + "\n"; // cria String nova a cada volta
}

codeExample:
// Array: tamanho fixo, definido na criação
int[] numeros = new int[5];
numeros[0] = 10;
// numeros[5] = 1; // ArrayIndexOutOfBoundsException — não existe posição 5 num array de tamanho 5

// ArrayList: tamanho dinâmico
List<Integer> lista = new ArrayList<>();
lista.add(10);
lista.add(20);
lista.remove(0); // pode remover e continuar adicionando — array não permite isso

// Lista imutável (Java 9+): útil para constantes/valores que não devem mudar
List<String> cores = List.of("vermelho", "verde", "azul");

codeExampleBad:
int[] numeros = {1, 2, 3};

// Não existe "numeros.add(4)" — array não tem esse método, tamanho é fixo.
// Pra 'crescer' um array, você precisa criar um array NOVO maior e copiar tudo:
int[] maior = Arrays.copyOf(numeros, numeros.length + 1);
maior[maior.length - 1] = 4;
// Isso é exatamente o que ArrayList faz por baixo dos panos, automaticamente, por você.
